import React, { useEffect, useState } from "react";
import {
  Box,
  Typography,
  Button,
  CircularProgress,
  Alert,
  Paper,
} from "@mui/material";
import { getAllRiders, approveRider, rejectRider } from "../services/api";

export default function AdminDashboard() {
  const [riders, setRiders] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  useEffect(() => {
    getAllRiders()
      .then((res) => {
        setRiders(res.data.riders || []);
        setLoading(false);
      })
      .catch((err) => {
        setError("Error loading riders");
        setLoading(false);
      });
  }, []);

  if (loading) return <CircularProgress sx={{ m: 4 }} />;
  if (error) return <Alert severity="error">{error}</Alert>;

  return (
    <Box sx={{ p: 4 }}>
      <Typography variant="h4" sx={{ mb: 3 }}>
        Admin Dashboard
      </Typography>

      <Typography variant="h6" sx={{ mb: 2 }}>
        Rider Approvals
      </Typography>

      {riders.length === 0 ? (
        <Typography>No riders found.</Typography>
      ) : (
        riders.map((r) => (
          <Paper key={r._id} sx={{ p: 2, mb: 2 }}>
            <Typography>
              <strong>{r.fullName}</strong> ({r.mobile})
            </Typography>
            <Typography>Status: {r.approvalStatus}</Typography>
            <Box sx={{ mt: 1, display: "flex", gap: 2 }}>
              <Button
                variant="contained"
                color="success"
                onClick={() => approveRider(r._id).then(() => window.location.reload())}
              >
                Approve
              </Button>
              <Button
                variant="contained"
                color="error"
                onClick={() => rejectRider(r._id).then(() => window.location.reload())}
              >
                Reject
              </Button>
            </Box>
          </Paper>
        ))
      )}
    </Box>
  );
}
